prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelId ?modelOriginalId ?corpusId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?modelOriginalId . }
  OPTIONAL { ?org tai:belongsTo ?corpus . ?org tai:corpusId ?corpusId . }
  FILTER(
    STR(?modelId) = "fbb0adafe6924f58ac902063a36646fe" ||
    STR(?modelOriginalId) = "fbb0adafe6924f58ac902063a36646fe"
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?type ?name ?modelId WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId ?origId .
  FILTER(STR(?origId) = "fbb0adafe6924f58ac902063a36646fe")
  OPTIONAL { ?model tai:normalizedId ?modelId . }

  ?elem tai:belongsTo ?choreoOrDefs .
  { ?choreoOrDefs tai:belongsTo ?model . } 
  UNION
  { ?choreoOrDefs tai:belongsTo ?model2 . ?model2 tai:originalId ?origId . }

  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 25
